cat > /tmp/read_binlog.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild(args[0]);

Console.WriteLine("=== ERRORS ===");
build.VisitAllChildren<Error>(e => {
    Console.WriteLine($"  [{e.ProjectFile}]");
    Console.WriteLine($"  File: {e.File} Line: {e.LineNumber}");
    Console.WriteLine($"  Code: {e.Code}");
    Console.WriteLine($"  Message: {e.Message}");
    Console.WriteLine();
});

Console.WriteLine("=== WARNINGS ===");
build.VisitAllChildren<Warning>(w => {
    Console.WriteLine($"  [{w.ProjectFile}] {w.Code}: {w.Message}");
});

Console.WriteLine("\n=== PROJECT GRAPH ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"  Project: {p.Name} -> Succeeded: {p.Succeeded}");
});

Console.WriteLine("\n=== EMBEDDED FILES ===");
var archives = build.SourceFilesArchive;
if (archives != null) {
    Console.WriteLine($"  Archive has {archives.Files?.Count ?? 0} files");
    if (archives.Files != null) {
        foreach (var f in archives.Files) {
            Console.WriteLine($"  File: {f.FullPath}");
            Console.WriteLine(f.Text);
            Console.WriteLine("---");
        }
    }
}
