arguments.command:
# Fix the reader tool - build in isolated directory
mkdir -p /tmp/binlog_reader && cd /tmp/binlog_reader
cat > Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild(args[0]);

Console.WriteLine("=== ERRORS ===");
build.VisitAllChildren<Error>(e => {
    Console.WriteLine($"  Project: {e.ProjectFile}");
    Console.WriteLine($"  File: {e.File} Line: {e.LineNumber}");
    Console.WriteLine($"  Code: {e.Code}");
    Console.WriteLine($"  Message: {e.Message}");
    Console.WriteLine();
});

Console.WriteLine("=== WARNINGS ===");
build.VisitAllChildren<Warning>(w => {
    Console.WriteLine($"  [{w.ProjectFile}] {w.Code}: {w.Message}");
});

Console.WriteLine("\n=== PROJECT OUTCOMES ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"  {p.Name} -> Succeeded: {p.Succeeded}");
});

Console.WriteLine("\n=== EMBEDDED SOURCE FILES ===");
try {
    var archives = build.SourceFilesArchive;
    if (archives != null) {
        Console.WriteLine($"  Archive exists, Children: {archives.Children?.Count ?? 0}");
        foreach (var child in archives.Children ?? Enumerable.Empty<BaseNode>()) {
            if (child is SourceFile sf) {
                Console.WriteLine($"\n--- {sf.Name} ---");
                Console.WriteLine(sf.Value);
            } else {
                Console.WriteLine($"  Child type: {child.GetType().Name}, Name: {child.ToString()?.Substring(0, Math.Min(100, child.ToString()?.Length ?? 0))}");
            }
        }
    } else {
        Console.WriteLine("  No archive found");
    }
} catch (Exception ex) {
    Console.WriteLine($"  Error reading archives: {ex.Message}");
}
CSHARP

